const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PRICE = 60;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

function componentBasePremium(count: number, unitPrice: number): number {
  return count === COMPONENT_BLOCK_SIZE
    ? COMPONENT_BLOCK_PRICE
    : count * unitPrice;
}

export function quote(_customer: Customer, items: Item[]): number {
  const runeCount = items.filter((i) => i.type === "rune").length;
  const moonstoneCount = items.filter((i) => i.type === "moonstone").length;
  const otherBase = items
    .filter((i) => i.type !== "rune" && i.type !== "moonstone")
    .reduce((total, item) => total + BASE_PREMIUMS[item.type], 0);
  const itemsBase =
    otherBase +
    componentBasePremium(runeCount, BASE_PREMIUMS.rune) +
    componentBasePremium(moonstoneCount, BASE_PREMIUMS.moonstone);
  const insuranceSurcharge = itemsBase * INSURANCE_SURCHARGE_RATE;
  return Math.ceil(itemsBase + insuranceSurcharge + PROCESSING_FEE);
}
